CREATE OR REPLACE TABLE `my-mimic-research.my_results.aki_cohort_selected_features` AS
(
WITH

Base_Cohort AS (
  SELECT
      subject_id, hadm_id, admittime, stay_id
  FROM (
      SELECT
          icu.subject_id, adm.hadm_id, adm.admittime, icu.stay_id,
          ROW_NUMBER() OVER (PARTITION BY icu.subject_id ORDER BY icu.intime ASC) as icu_stay_rank
      FROM `physionet-data.mimiciv_3_1_icu.icustays` AS icu
      INNER JOIN `physionet-data.mimiciv_3_1_hosp.admissions` AS adm ON icu.hadm_id = adm.hadm_id
      INNER JOIN `physionet-data.mimiciv_3_1_hosp.patients` AS pat ON icu.subject_id = pat.subject_id
      WHERE
          icu.los > 1 AND (EXTRACT(YEAR FROM adm.admittime) - pat.anchor_year + pat.anchor_age) >= 18
          AND EXISTS (
              SELECT 1 FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` d
              WHERE d.hadm_id = icu.hadm_id
                AND ((d.icd_version = 9 AND (d.icd_code LIKE '584%' OR d.icd_code = '586'))
                     OR (d.icd_version = 10 AND (d.icd_code LIKE 'N17%' OR d.icd_code = 'N19')))
          )
  ) AS ranked_stays
  WHERE icu_stay_rank = 1
),
First_ICU_Stay AS (
  SELECT hadm_id, stay_id, intime, outtime, los AS icu_los_raw
  FROM (
       SELECT hadm_id, stay_id, intime, outtime, los,
       ROW_NUMBER() OVER (PARTITION BY hadm_id ORDER BY intime ASC) as rn
       FROM `physionet-data.mimiciv_3_1_icu.icustays`
  ) AS ranked_icustays
  WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND rn = 1
),


Relevant_AKI_Codes AS (SELECT hadm_id, STRING_AGG(icd_code, ', ') AS aki_icd_code FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` d WHERE (d.icd_version = 9 AND (d.icd_code LIKE '584%' OR d.icd_code = '586')) OR (d.icd_version = 10 AND (d.icd_code LIKE 'N17%' OR d.icd_code = 'N19')) AND hadm_id IN (SELECT hadm_id FROM Base_Cohort) GROUP BY hadm_id),
Pregnancy_Codes AS (SELECT hadm_id, STRING_AGG(icd_code, ', ') AS pregnancy_icd_codes FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE ((icd_version = 10 AND REGEXP_CONTAINS(icd_code, r'^Z3[3469]')) OR (icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^V2[234]'))) AND hadm_id IN (SELECT hadm_id FROM Base_Cohort) GROUP BY hadm_id),
Congenital_Codes AS (SELECT hadm_id, STRING_AGG(icd_code, ', ') AS congenital_anomaly_icd_codes FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE ((icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^(74|75)')) OR (icd_version = 10 AND REGEXP_CONTAINS(icd_code, r'^Q'))) AND hadm_id IN (SELECT hadm_id FROM Base_Cohort) GROUP BY hadm_id),
Hematolymphoid_Malignancy_Codes AS (SELECT hadm_id, STRING_AGG(icd_code, ', ' ORDER BY icd_code) AS hematolymphoid_icd_codes FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND ((icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^(20[0-8]|1985|2384|2387[2-6])')) OR (icd_version = 10 AND REGEXP_CONTAINS(icd_code, r'^(C8[1-68]|C9[0-5]|D4[567]|C7952)'))) GROUP BY hadm_id),
Malignancy_Codes AS (SELECT hadm_id, STRING_AGG(icd_code, ', ') AS malignancy_icd_codes FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE ((icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^(1[4-9]|20)')) OR (icd_version = 10 AND REGEXP_CONTAINS(icd_code, r'^C'))) AND hadm_id IN (SELECT hadm_id FROM Base_Cohort) GROUP BY hadm_id),
AIDS_Codes AS (SELECT hadm_id, STRING_AGG(icd_code, ', ') AS aids_icd_codes FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND (icd_code IN ('B20', 'V08', '042') OR (icd_version = 10 AND icd_code LIKE 'O987%')) GROUP BY hadm_id),

Comorbidities_Flags AS (
    SELECT hadm_id,
        MAX(CASE WHEN (icd_version = 10 AND icd_code LIKE 'E10%') THEN 1 ELSE 0 END) AS has_t1d,
        MAX(CASE WHEN (icd_version = 10 AND icd_code LIKE 'E11%') THEN 1 ELSE 0 END) AS has_t2d,
        MAX(CASE WHEN icd_code IN ('4010', '4011', '4019') OR (icd_version = 10 AND icd_code LIKE 'I10%') THEN 1 ELSE 0 END) AS has_hypertension,
        MAX(CASE WHEN (icd_version = 9 AND icd_code LIKE '428%') OR (icd_version = 10 AND (icd_code LIKE 'I50%' OR icd_code IN ('I110', 'I13', 'I9713', 'I0981'))) THEN 1 ELSE 0 END) AS has_heart_failure,
        MAX(CASE WHEN (icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^43[0-8]')) OR (icd_version = 10 AND REGEXP_CONTAINS(icd_code, r'^I6')) THEN 1 ELSE 0 END) AS has_cerebrovascular_disease,
        MAX(CASE WHEN (icd_version = 9 AND icd_code IN ('51851', '51853', '51881', '51884', '51883', '51882')) OR (icd_version = 10 AND (icd_code IN ('J95822', 'J95821') OR icd_code LIKE 'J96%')) THEN 1 ELSE 0 END) AS has_respiratory_failure,
        MAX(CASE WHEN (icd_version = 9 AND (icd_code LIKE '038%' OR icd_code IN ('0202', '0223'))) OR (icd_version = 10 AND (icd_code LIKE 'A40%' OR icd_code LIKE 'A41%' OR icd_code IN ('O85', 'A427', 'B377', 'A267', 'A282', 'A5486', 'A327', 'A392', 'A393', 'A394', 'A207', 'A217', 'A483', 'A227'))) THEN 1 ELSE 0 END) AS has_sepsis,
        MAX(CASE WHEN (icd_version = 9 AND icd_code IN ('5715', '5712', '5716')) OR (icd_version = 10 AND (icd_code LIKE 'K703%' OR icd_code LIKE 'K721%' OR icd_code IN ('K702', 'K704', 'K740', 'K741', 'K742', 'K743', 'K744', 'K745', 'K746'))) THEN 1 ELSE 0 END) AS has_cirrhosis,
        MAX(CASE WHEN (icd_version = 9 AND icd_code IN ('5851', '5852', '5853', '5854', '5855', '5856', '5859', '28521', '403', '404')) OR (icd_version = 10 AND (icd_code LIKE 'E102%' OR icd_code LIKE 'E112%' OR icd_code LIKE 'E132%' OR icd_code LIKE 'I12%' OR icd_code LIKE 'I13%' OR icd_code LIKE 'N18%' OR icd_code LIKE 'N03%' OR icd_code LIKE 'N04%' OR icd_code LIKE 'N05%' OR icd_code LIKE 'N11%' OR icd_code IN ('I150', 'I151', 'N19', 'N12', 'N14', 'N15', 'N16', 'N00', 'N01', 'N02', 'N06', 'N07', 'N08', 'M3214', 'M3215', 'M3504', 'M350A'))) THEN 1 ELSE 0 END) AS has_ckd,
        MAX(CASE WHEN (icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^20[4-8]')) OR (icd_version = 10 AND REGEXP_CONTAINS(icd_code, r'^C9[1-5]')) THEN 1 ELSE 0 END) AS has_leukemia,
        MAX(CASE WHEN (icd_version = 9 AND REGEXP_CONTAINS(icd_code, r'^20[0-2]')) OR (icd_version = 10 AND (icd_code LIKE 'C81%' OR icd_code LIKE 'C82%' OR icd_code LIKE 'C83%' OR icd_code LIKE 'C84%' OR icd_code LIKE 'C85%' OR icd_code LIKE 'C86%' OR icd_code LIKE 'C88%')) THEN 1 ELSE 0 END) AS has_lymphoma,
        MAX(CASE WHEN icd_code IN ('B20', 'V08', '042') OR (icd_version = 10 AND icd_code LIKE 'O987%') THEN 1 ELSE 0 END) AS has_aids
    FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort) GROUP BY hadm_id
),
Patient_History AS (
  WITH All_Hemo_Events AS (
      SELECT subject_id, CAST(chartdate AS DATETIME) AS event_time FROM `physionet-data.mimiciv_3_1_hosp.procedures_icd` WHERE icd_code IN ('3995', '3927', '3943', '3895', '3942', '5A1D70Z', '5A1D80Z', '5A1D90Z')
      UNION ALL SELECT i.subject_id, ce.charttime AS event_time FROM `physionet-data.mimiciv_3_1_icu.chartevents` ce JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON ce.stay_id = i.stay_id WHERE ce.itemid IN (226118, 227357, 225725, 226499, 224154, 225183, 227438, 224191, 228004, 228005, 228006, 224144, 224145, 224149, 224150, 224151, 224152, 224153)
      UNION ALL SELECT adm.subject_id, adm.admittime AS event_time FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` d JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON d.hadm_id = adm.hadm_id WHERE d.icd_code = 'Z992'
  ), All_PD_Events AS (
      SELECT subject_id, CAST(chartdate AS DATETIME) AS event_time FROM `physionet-data.mimiciv_3_1_hosp.procedures_icd` WHERE icd_code = '5498'
      UNION ALL SELECT i.subject_id, ce.charttime AS event_time FROM `physionet-data.mimiciv_3_1_icu.chartevents` ce JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON ce.stay_id = i.stay_id WHERE ce.itemid IN (225810, 225806, 225807, 227639, 225959, 225951, 225952, 225961, 225953, 225963, 225965, 227638, 227640)
  ), All_Transplant_Events AS (
      SELECT subject_id, CAST(chartdate AS DATETIME) AS event_time FROM `physionet-data.mimiciv_3_1_hosp.procedures_icd` WHERE (icd_version = 9 AND icd_code IN ('5569', '5553')) OR (icd_version = 10 AND icd_code IN ('0TY00Z0', '0TY00Z1', '0TY00Z2', '0TY10Z0', '0TY10Z1', '0TY10Z2'))
  )
  SELECT bc.hadm_id, MAX(IF(hemo.event_time < bc.admittime, 1, 0)) AS history_hemodialysis, MAX(IF(pd.event_time < bc.admittime, 1, 0)) AS had_peritoneal_dialysis, MAX(IF(transplant.event_time < bc.admittime, 1, 0)) AS history_renal_transplant
  FROM Base_Cohort bc LEFT JOIN All_Hemo_Events hemo ON bc.subject_id = hemo.subject_id LEFT JOIN All_PD_Events pd ON bc.subject_id = pd.subject_id LEFT JOIN All_Transplant_Events transplant ON bc.subject_id = transplant.subject_id
  GROUP BY bc.hadm_id
),
NIV_Flag AS (SELECT hadm_id, 1 AS had_niv FROM (SELECT i.hadm_id FROM `physionet-data.mimiciv_3_1_icu.procedureevents` pe JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON pe.stay_id = i.stay_id WHERE i.hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND pe.itemid = 225794 UNION DISTINCT SELECT i.hadm_id FROM `physionet-data.mimiciv_3_1_icu.chartevents` c JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON c.stay_id = i.stay_id WHERE i.hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND ((c.itemid = 226732 AND c.value IN ('Bipap mask', 'CPAP mask')) OR (c.itemid = 229314 AND c.value IN ('DuoPaP', 'NIV', 'NIV-ST')))) GROUP BY hadm_id),
IMV_Flag AS (SELECT hadm_id, 1 AS had_imv FROM (SELECT i.hadm_id FROM `physionet-data.mimiciv_3_1_icu.procedureevents` pe JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON pe.stay_id = i.stay_id WHERE i.hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND pe.itemid = 225792 UNION DISTINCT SELECT i.hadm_id FROM `physionet-data.mimiciv_3_1_icu.chartevents` c JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON c.stay_id = i.stay_id WHERE i.hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND ((c.itemid = 226732 AND c.value IN ('Endotracheal tube', 'Trach mask')) OR (c.itemid = 223849) OR (c.itemid = 229314 AND c.value IN ('APRV', 'APV (cmv)', 'Ambient', '(S) CMV', 'P-CMV', 'SIMV', 'APV (simv)', 'P-SIMV', 'VS', 'ASV')))) GROUP BY hadm_id),
RRT_Flag AS (SELECT hadm_id, 1 AS had_rrt FROM `physionet-data.mimiciv_3_1_hosp.procedures_icd` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND ((icd_version = 9 AND icd_code IN ('3995', '3927', '3943', '3895', '3942', '5498')) OR (icd_version = 10 AND icd_code IN ('5A1D70Z', '5A1D80Z', '5A1D90Z'))) GROUP BY hadm_id),
Baseline_Creatinine AS (WITH all_creat AS (SELECT p.subject_id, le.charttime, le.valuenum FROM `physionet-data.mimiciv_3_1_hosp.patients` p JOIN `physionet-data.mimiciv_3_1_hosp.labevents` le ON p.subject_id = le.subject_id WHERE le.itemid = 50912 AND le.valuenum IS NOT NULL AND le.valuenum > 0 AND p.subject_id IN (SELECT subject_id FROM Base_Cohort)), creat_by_admission AS (SELECT bc.hadm_id, bc.admittime, bc.subject_id, MIN(IF(cr.charttime BETWEEN DATETIME_SUB(bc.admittime, INTERVAL 12 MONTH) AND DATETIME_SUB(bc.admittime, INTERVAL 24 HOUR), cr.valuenum, NULL)) AS creat_12mo_24hr_prior, MIN(IF(cr.charttime < bc.admittime AND cr.charttime >= DATETIME_SUB(bc.admittime, INTERVAL 24 HOUR), cr.valuenum, NULL)) AS creat_24hr_prior FROM Base_Cohort bc LEFT JOIN all_creat cr ON bc.subject_id = cr.subject_id GROUP BY bc.hadm_id, bc.admittime, bc.subject_id) SELECT cba.hadm_id, COALESCE(cba.creat_12mo_24hr_prior, cba.creat_24hr_prior, (0.74 - (0.2 * IF(pat.gender = 'F', 1, 0)) + (0.08 * IF(adm.race LIKE '%BLACK%', 1, 0)) + (0.003 * (EXTRACT(YEAR FROM adm.admittime) - pat.anchor_year + pat.anchor_age)))) AS baseline_creatinine FROM creat_by_admission cba JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON cba.hadm_id = adm.hadm_id JOIN `physionet-data.mimiciv_3_1_hosp.patients` pat ON adm.subject_id = pat.subject_id),


Baseline_Features AS (
    WITH Time_Window AS (SELECT stay_id, intime, DATETIME_SUB(intime, INTERVAL 24 HOUR) as window_start, DATETIME_ADD(intime, INTERVAL 24 HOUR) as window_end FROM First_ICU_Stay),
    all_events_unioned AS (
        SELECT tw.stay_id, fis.hadm_id, ev.charttime, ev.itemid,
            CASE
                WHEN ev.itemid IN (52769, 53132, 51253, 51199) THEN ev.valuenum / 1000
                ELSE ev.valuenum
            END AS valuenum,
            ev.comments AS comment_val
        FROM Time_Window tw
        INNER JOIN First_ICU_Stay fis ON tw.stay_id = fis.stay_id
        INNER JOIN `physionet-data.mimiciv_3_1_hosp.labevents` ev ON fis.hadm_id = ev.hadm_id
        WHERE ev.charttime BETWEEN tw.window_start AND tw.window_end
        UNION ALL
        SELECT tw.stay_id, fis.hadm_id, ev.charttime, ev.itemid, ev.valuenum, ev.value AS comment_val
        FROM Time_Window tw
        INNER JOIN First_ICU_Stay fis ON tw.stay_id = fis.stay_id
        INNER JOIN `physionet-data.mimiciv_3_1_icu.chartevents` ev ON tw.stay_id = ev.stay_id
        WHERE ev.charttime BETWEEN tw.window_start AND tw.window_end
    ),
    events_ranked AS (
        SELECT hadm_id, stay_id, valuenum,
            CASE
                WHEN itemid IN (220045) THEN 'heart_rate'
                WHEN itemid IN (220052, 220181, 225312) THEN 'mbp'
                WHEN itemid IN (223761) THEN 'temp_f'
                WHEN itemid IN (223901) THEN 'gcs_motor'
                WHEN itemid IN (223900) THEN 'gcs_verbal'
                WHEN itemid IN (220739) THEN 'gcs_eye'
                WHEN itemid IN (50811, 51640, 51222) THEN 'hb'
                WHEN itemid IN (51300, 51301, 51755, 220546) THEN 'wbc'
                WHEN itemid IN (51248) THEN 'mch'
                WHEN itemid IN (51691, 51250) THEN 'mcv'
                WHEN itemid IN (51277) THEN 'rdw_cv'
                WHEN itemid IN (51704, 51265) THEN 'platelet_count'
                WHEN itemid IN (52075, 53133) THEN 'abs_neutrophil'
                WHEN itemid IN (52769, 51133, 53132) THEN 'abs_lymphocyte'
                WHEN itemid IN (51253, 52074) THEN 'abs_monocyte'
                WHEN itemid IN (50931, 50809, 52569, 52027) THEN 'glucose_lab'
                WHEN itemid IN (50904, 220624) THEN 'hdl'
                WHEN itemid IN (50912, 52546, 52024) THEN 'creatinine'
                WHEN itemid IN (51842, 52647, 51006) THEN 'bun'
                WHEN itemid IN (50862, 53085, 52022, 53138, 227456, 220574) THEN 'albumin'
                WHEN itemid IN (50821, 220224) THEN 'pao2'
                WHEN itemid IN (50820, 223830) THEN 'ph_arterial'
            END AS concept,
            ROW_NUMBER() OVER (PARTITION BY hadm_id,
                CASE
                    WHEN itemid IN (220045) THEN 'heart_rate' WHEN itemid IN (220052, 220181, 225312) THEN 'mbp' WHEN itemid IN (223761) THEN 'temp_f' WHEN itemid IN (223901) THEN 'gcs_motor' WHEN itemid IN (223900) THEN 'gcs_verbal' WHEN itemid IN (220739) THEN 'gcs_eye' WHEN itemid IN (50811, 51640, 51222) THEN 'hb' WHEN itemid IN (51300, 51301, 51755, 220546) THEN 'wbc' WHEN itemid IN (51248) THEN 'mch' WHEN itemid IN (51691, 51250) THEN 'mcv' WHEN itemid IN (51277) THEN 'rdw_cv' WHEN itemid IN (51704, 51265) THEN 'platelet_count' WHEN itemid IN (52075, 53133) THEN 'abs_neutrophil' WHEN itemid IN (52769, 51133, 53132) THEN 'abs_lymphocyte' WHEN itemid IN (51253, 52074) THEN 'abs_monocyte' WHEN itemid IN (50931, 50809, 52569, 52027) THEN 'glucose_lab' WHEN itemid IN (50904, 220624) THEN 'hdl' WHEN itemid IN (50912, 52546, 52024) THEN 'creatinine' WHEN itemid IN (51842, 52647, 51006) THEN 'bun' WHEN itemid IN (50862, 53085, 52022, 53138, 227456, 220574) THEN 'albumin' WHEN itemid IN (50821, 220224) THEN 'pao2' WHEN itemid IN (50820, 223830) THEN 'ph_arterial'
                END
            ORDER BY charttime ASC) AS rn
        FROM all_events_unioned
    ),
    First_Day_Values AS (
        SELECT hadm_id,
            MAX(CASE WHEN concept = 'heart_rate' THEN valuenum END) AS first_heart_rate, MAX(CASE WHEN concept = 'mbp' THEN valuenum END) AS first_mbp, MAX(CASE WHEN concept = 'temp_f' THEN valuenum END) AS first_temp_f, MAX(CASE WHEN concept = 'gcs_motor' THEN valuenum END) AS first_gcs_motor, MAX(CASE WHEN concept = 'gcs_verbal' THEN valuenum END) AS first_gcs_verbal, MAX(CASE WHEN concept = 'gcs_eye' THEN valuenum END) AS first_gcs_eye, MAX(CASE WHEN concept = 'hb' THEN valuenum END) AS first_hb, MAX(CASE WHEN concept = 'wbc' THEN valuenum END) AS first_wbc, MAX(CASE WHEN concept = 'mch' THEN valuenum END) AS first_mch, MAX(CASE WHEN concept = 'mcv' THEN valuenum END) AS first_mcv, MAX(CASE WHEN concept = 'rdw_cv' THEN valuenum END) AS first_rdw_cv, MAX(CASE WHEN concept = 'platelet_count' THEN valuenum END) AS first_platelet_count, MAX(CASE WHEN concept = 'abs_neutrophil' THEN valuenum END) AS first_abs_neutrophil, MAX(CASE WHEN concept = 'abs_lymphocyte' THEN valuenum END) AS first_abs_lymphocyte, MAX(CASE WHEN concept = 'abs_monocyte' THEN valuenum END) AS first_abs_monocyte, MAX(CASE WHEN concept = 'glucose_lab' THEN valuenum END) AS first_glucose_lab, MAX(CASE WHEN concept = 'hdl' THEN valuenum END) AS first_hdl, MAX(CASE WHEN concept = 'creatinine' THEN valuenum END) AS first_creatinine, MAX(CASE WHEN concept = 'bun' THEN valuenum END) AS first_bun, MAX(CASE WHEN concept = 'albumin' THEN valuenum END) AS first_albumin, MAX(CASE WHEN concept = 'pao2' THEN valuenum END) AS first_pao2, MAX(CASE WHEN concept = 'ph_arterial' THEN valuenum END) AS first_ph_arterial
        FROM events_ranked WHERE rn = 1 GROUP BY hadm_id
    )
    SELECT bc.hadm_id, fdv.* EXCEPT(hadm_id)
    FROM Base_Cohort AS bc LEFT JOIN First_Day_Values as fdv ON bc.hadm_id = fdv.hadm_id
),
MAKE_Creatinine_Outcomes AS (
   WITH all_creat_values AS (
       SELECT bc.hadm_id, le.charttime, le.valuenum, ROW_NUMBER() OVER(PARTITION BY bc.hadm_id ORDER BY le.charttime DESC) as rn_desc
       FROM Base_Cohort bc JOIN First_ICU_Stay icu ON bc.hadm_id = icu.hadm_id JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON bc.hadm_id = adm.hadm_id JOIN `physionet-data.mimiciv_3_1_hosp.labevents` le ON bc.hadm_id = le.hadm_id
       WHERE le.itemid IN (50912, 52546, 52024) AND le.charttime <= LEAST(adm.dischtime, DATETIME_ADD(icu.intime, INTERVAL 30 DAY))
   ), final_creat AS (
       SELECT hadm_id, valuenum as make_final_creat_value FROM all_creat_values WHERE rn_desc = 1
   )
   SELECT fc.hadm_id, fc.make_final_creat_value
   FROM final_creat fc
),
Current_Renal_Transplant AS (WITH first_transplant AS (SELECT hadm_id, CAST(chartdate AS DATETIME) as transplant_chartdate, ROW_NUMBER() OVER(PARTITION BY hadm_id ORDER BY chartdate ASC) as rn FROM `physionet-data.mimiciv_3_1_hosp.procedures_icd` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort) AND ((icd_version = 9 AND icd_code = '5569') OR (icd_version = 10 AND icd_code IN ('0TY00Z0', '0TY00Z1', '0TY00Z2', '0TY10Z0', '0TY10Z1', '0TY10Z2')))) SELECT hadm_id, 1 AS renal_transplant_current, transplant_chartdate FROM first_transplant WHERE rn=1),
Charlson_Index AS (WITH diag AS (SELECT hadm_id, CASE WHEN icd_version = 9 THEN icd_code ELSE NULL END AS icd9_code, CASE WHEN icd_version = 10 THEN icd_code ELSE NULL END AS icd10_code FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort)), com AS (SELECT hadm_id, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('410', '412') OR SUBSTR(icd10_code, 1, 3) IN ('I21', 'I22') OR SUBSTR(icd10_code, 1, 4) = 'I252' THEN 1 ELSE 0 END) AS myocardial_infarct, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) = '428' OR SUBSTR(icd9_code, 1, 5) IN ('39891', '40201', '40211', '40291', '40401', '40403', '40411', '40413', '40491', '40493') OR SUBSTR(icd9_code, 1, 4) BETWEEN '4254' AND '4259' OR SUBSTR(icd10_code, 1, 3) IN ('I43', 'I50') OR SUBSTR(icd10_code, 1, 4) IN ('I099', 'I110', 'I130', 'I132', 'I255', 'I420', 'I425', 'I426', 'I427', 'I428', 'I429', 'P290') THEN 1 ELSE 0 END) AS congestive_heart_failure, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('440', '441') OR SUBSTR(icd9_code, 1, 4) IN ('0930', '4373', '4471', '5571', '5579', 'V434') OR SUBSTR(icd9_code, 1, 4) BETWEEN '4431' AND '4439' OR SUBSTR(icd10_code, 1, 3) IN ('I70', 'I71') OR SUBSTR(icd10_code, 1, 4) IN ('I731', 'I738', 'I739', 'I771', 'I790', 'I792', 'K551', 'K558', 'K559', 'Z958', 'Z959') THEN 1 ELSE 0 END) AS peripheral_vascular_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) BETWEEN '430' AND '438' OR SUBSTR(icd9_code, 1, 5) = '36234' OR SUBSTR(icd10_code, 1, 3) IN ('G45', 'G46') OR SUBSTR(icd10_code, 1, 3) BETWEEN 'I60' AND 'I69' OR SUBSTR(icd10_code, 1, 4) = 'H340' THEN 1 ELSE 0 END) AS cerebrovascular_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) = '290' OR SUBSTR(icd9_code, 1, 4) IN ('2941', '3312') OR SUBSTR(icd10_code, 1, 3) IN ('F00', 'F01', 'F02', 'F03', 'G30') OR SUBSTR(icd10_code, 1, 4) IN ('F051', 'G311') THEN 1 ELSE 0 END) AS dementia, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) BETWEEN '490' AND '505' OR SUBSTR(icd9_code, 1, 4) IN ('4168', '4169', '5064', '5081', '5088') OR SUBSTR(icd10_code, 1, 3) BETWEEN 'J40' AND 'J47' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'J60' AND 'J67' OR SUBSTR(icd10_code, 1, 4) IN ('I278', 'I279', 'J684', 'J701', 'J703') THEN 1 ELSE 0 END) AS chronic_pulmonary_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) = '725' OR SUBSTR(icd9_code, 1, 4) IN ('4465', '7100', '7101', '7102', '7103', '7104', '7140', '7141', '7142', '7148') OR SUBSTR(icd10_code, 1, 3) IN ('M05', 'M06', 'M32', 'M33', 'M34') OR SUBSTR(icd10_code, 1, 4) IN ('M315', 'M351', 'M353', 'M360') THEN 1 ELSE 0 END) AS rheumatic_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('531', '532', '533', '534') OR SUBSTR(icd10_code, 1, 3) IN ('K25', 'K26', 'K27', 'K28') THEN 1 ELSE 0 END) AS peptic_ulcer_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('570', '571') OR SUBSTR(icd9_code, 1, 4) IN ('0706', '0709', '5733', '5734', '5738', '5739', 'V427') OR SUBSTR(icd9_code, 1, 5) IN ('07022', '07023', '07032', '07033', '07044', '07054') OR SUBSTR(icd10_code, 1, 3) IN ('B18', 'K73', 'K74') OR SUBSTR(icd10_code, 1, 4) IN ('K700', 'K701', 'K702', 'K703', 'K709', 'K713', 'K714', 'K715', 'K717', 'K760', 'K762', 'K763', 'K764', 'K768', 'K769', 'Z944') THEN 1 ELSE 0 END) AS mild_liver_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 4) IN ('2500', '2501', '2502', '2503', '2508', '2509') OR SUBSTR(icd10_code, 1, 4) IN ('E100', 'E101', 'E106', 'E108', 'E109', 'E110', 'E111', 'E116', 'E118', 'E119', 'E120', 'E121', 'E126', 'E128', 'E129', 'E130', 'E131', 'E136', 'E138', 'E139', 'E140', 'E141', 'E146', 'E148', 'E149') THEN 1 ELSE 0 END) AS diabetes_without_cc, MAX(CASE WHEN SUBSTR(icd9_code, 1, 4) IN ('2504', '2505', '2506', '2507') OR SUBSTR(icd10_code, 1, 4) IN ('E102', 'E103', 'E104', 'E105', 'E107', 'E112', 'E113', 'E114', 'E115', 'E117', 'E122', 'E123', 'E124', 'E125', 'E127', 'E132', 'E133', 'E134', 'E135', 'E137', 'E142', 'E143', 'E144', 'E145', 'E147') THEN 1 ELSE 0 END) AS diabetes_with_cc, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('342', '343') OR SUBSTR(icd9_code, 1, 4) IN ('3341', '3440', '3441', '3442', '3443', '3444', '3445', '3446', '3449') OR SUBSTR(icd10_code, 1, 3) IN ('G81', 'G82') OR SUBSTR(icd10_code, 1, 4) IN ('G041', 'G114', 'G801', 'G802', 'G830', 'G831', 'G832', 'G833', 'G834', 'G839') THEN 1 ELSE 0 END) AS paraplegia, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('582', '585', '586', 'V56') OR SUBSTR(icd9_code, 1, 4) IN ('5880', 'V420', 'V451') OR SUBSTR(icd9_code, 1, 4) BETWEEN '5830' AND '5837' OR SUBSTR(icd9_code, 1, 5) IN ('40301', '40311', '40391', '40402', '40403', '40412', '40413', '40492', '40493') OR SUBSTR(icd10_code, 1, 3) IN ('N18', 'N19') OR SUBSTR(icd10_code, 1, 4) IN ('I120', 'I131', 'N032', 'N033', 'N034', 'N035', 'N036', 'N037', 'N052', 'N053', 'N054', 'N055', 'N056', 'N057', 'N250', 'Z490', 'Z491', 'Z492', 'Z940', 'Z992') THEN 1 ELSE 0 END) AS renal_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) BETWEEN '140' AND '172' OR SUBSTR(icd9_code, 1, 4) BETWEEN '1740' AND '1958' OR SUBSTR(icd9_code, 1, 3) BETWEEN '200' AND '208' OR SUBSTR(icd9_code, 1, 4) = '2386' OR SUBSTR(icd10_code, 1, 3) IN ('C43', 'C88') OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C00' AND 'C26' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C30' AND 'C34' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C37' AND 'C41' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C45' AND 'C58' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C60' AND 'C76' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C81' AND 'C85' OR SUBSTR(icd10_code, 1, 3) BETWEEN 'C90' AND 'C97' THEN 1 ELSE 0 END) AS malignant_cancer, MAX(CASE WHEN SUBSTR(icd9_code, 1, 4) IN ('4560', '4561', '4562') OR SUBSTR(icd9_code, 1, 4) BETWEEN '5722' AND '5728' OR SUBSTR(icd10_code, 1, 4) IN ('I850', 'I859', 'I864', 'I982', 'K704', 'K711', 'K721', 'K729', 'K765', 'K766', 'K767') THEN 1 ELSE 0 END) AS severe_liver_disease, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('196', '197', '198', '199') OR SUBSTR(icd10_code, 1, 3) IN ('C77', 'C78', 'C79', 'C80') THEN 1 ELSE 0 END) AS metastatic_solid_tumor, MAX(CASE WHEN SUBSTR(icd9_code, 1, 3) IN ('042', '043', '044') OR SUBSTR(icd10_code, 1, 3) IN ('B20', 'B21', 'B22', 'B24') THEN 1 ELSE 0 END) AS aids FROM diag GROUP BY hadm_id), ag AS (SELECT hadm_id, age, CASE WHEN age <= 50 THEN 0 WHEN age <= 60 THEN 1 WHEN age <= 70 THEN 2 WHEN age <= 80 THEN 3 ELSE 4 END AS age_score FROM `physionet-data.mimiciv_3_1_derived.age` WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort)) SELECT com.hadm_id, ag.age_score + myocardial_infarct + congestive_heart_failure + peripheral_vascular_disease + cerebrovascular_disease + dementia + chronic_pulmonary_disease + rheumatic_disease + peptic_ulcer_disease + GREATEST(mild_liver_disease, 3 * severe_liver_disease) + GREATEST(2 * diabetes_with_cc, diabetes_without_cc) + GREATEST(2 * malignant_cancer, 6 * metastatic_solid_tumor) + 2 * paraplegia + 2 * renal_disease + 6 * aids AS charlson_comorbidity_index FROM com LEFT JOIN ag ON com.hadm_id = ag.hadm_id),
LODS_Scores AS (WITH cohort_with_intime AS (SELECT arf.subject_id, arf.hadm_id, arf.stay_id, icu.intime FROM Base_Cohort arf LEFT JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON arf.stay_id = icu.stay_id), ventilation_events AS (SELECT stay_id, charttime FROM `physionet-data.mimiciv_3_1_icu.chartevents` WHERE itemid = 223849 AND value IS NOT NULL AND stay_id IN (SELECT stay_id FROM cohort_with_intime)), cpap AS (SELECT c.stay_id, MIN(DATETIME_SUB(ce.charttime, INTERVAL '1' HOUR)) AS starttime, MAX(DATETIME_ADD(ce.charttime, INTERVAL '4' HOUR)) AS endtime FROM cohort_with_intime c INNER JOIN `physionet-data.mimiciv_3_1_icu.chartevents` ce ON c.stay_id = ce.stay_id AND ce.charttime >= c.intime AND ce.charttime <= DATETIME_ADD(c.intime, INTERVAL '1' DAY) WHERE ce.itemid = 226732 AND (LOWER(ce.value) LIKE '%cpap%' OR LOWER(ce.value) LIKE '%bipap mask%') GROUP BY c.stay_id), pafi1 AS (SELECT c.stay_id, bg.charttime, pao2fio2ratio, CASE WHEN vd.stay_id IS NOT NULL THEN 1 ELSE 0 END AS vent, CASE WHEN cp.stay_id IS NOT NULL THEN 1 ELSE 0 END AS cpap FROM `physionet-data.mimiciv_3_1_derived.bg` bg INNER JOIN cohort_with_intime c ON bg.hadm_id = c.hadm_id LEFT JOIN ventilation_events vd ON c.stay_id = vd.stay_id AND bg.charttime = vd.charttime LEFT JOIN cpap cp ON c.stay_id = cp.stay_id AND bg.charttime >= cp.starttime AND bg.charttime <= cp.endtime WHERE bg.charttime >= c.intime AND bg.charttime <= DATETIME_ADD(c.intime, INTERVAL '1' DAY)), pafi2 AS (SELECT stay_id, MIN(pao2fio2ratio) AS pao2fio2_vent_min FROM pafi1 WHERE vent = 1 OR cpap = 1 GROUP BY stay_id), cohort AS (SELECT ie.subject_id, ie.hadm_id, ie.stay_id, gcs.gcs_min, vital.heart_rate_max, vital.heart_rate_min, vital.sbp_max, vital.sbp_min, pf.pao2fio2_vent_min, labs.bun_max, labs.bun_min, labs.wbc_max, labs.wbc_min, labs.bilirubin_total_max AS bilirubin_max, labs.creatinine_max, labs.pt_min, labs.pt_max, labs.platelets_min AS platelet_min, uo.urineoutput FROM cohort_with_intime ie LEFT JOIN pafi2 pf ON ie.stay_id = pf.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_gcs` gcs ON ie.stay_id = gcs.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_vitalsign` vital ON ie.stay_id = vital.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_urine_output` uo ON ie.stay_id = uo.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_lab` labs ON ie.stay_id = labs.stay_id), scorecomp AS (SELECT cohort.*, CASE WHEN gcs_min < 3 THEN NULL WHEN gcs_min <= 5 THEN 5 WHEN gcs_min <= 8 THEN 3 WHEN gcs_min <= 13 THEN 1 ELSE 0 END AS neurologic, CASE WHEN heart_rate_min < 30 THEN 5 WHEN sbp_min < 40 THEN 5 WHEN sbp_min < 70 THEN 3 WHEN sbp_max >= 270 THEN 3 WHEN heart_rate_max >= 140 THEN 1 WHEN sbp_max >= 240 THEN 1 WHEN sbp_min < 90 THEN 1 ELSE 0 END AS cardiovascular, CASE WHEN urineoutput < 500.0 THEN 5 WHEN bun_max >= 56.0 THEN 5 WHEN creatinine_max >= 1.60 THEN 3 WHEN urineoutput < 750.0 THEN 3 WHEN bun_max >= 28.0 THEN 3 WHEN urineoutput >= 10000.0 THEN 3 WHEN creatinine_max >= 1.20 THEN 1 WHEN bun_max >= 17.0 THEN 1 WHEN bun_max >= 7.50 THEN 1 ELSE 0 END AS renal, CASE WHEN pao2fio2_vent_min IS NULL THEN 0 WHEN pao2fio2_vent_min >= 150 THEN 1 WHEN pao2fio2_vent_min < 150 THEN 3 END AS pulmonary, CASE WHEN wbc_min < 1.0 THEN 3 WHEN wbc_min < 2.5 THEN 1 WHEN platelet_min < 50.0 THEN 1 WHEN wbc_max >= 50.0 THEN 1 ELSE 0 END AS hematologic, CASE WHEN bilirubin_max >= 2.0 THEN 1 WHEN pt_max > (12 + 3) THEN 1 WHEN pt_min < (12 * 0.25) THEN 1 ELSE 0 END AS hepatic FROM cohort) SELECT s.stay_id, COALESCE(s.neurologic, 0) + COALESCE(s.cardiovascular, 0) + COALESCE(s.renal, 0) + COALESCE(s.pulmonary, 0) + COALESCE(s.hematologic, 0) + COALESCE(s.hepatic, 0) AS lods_score FROM scorecomp s),
First_Day_SOFA AS (WITH ventilation_events AS (SELECT stay_id, charttime FROM `physionet-data.mimiciv_3_1_icu.chartevents` WHERE itemid = 223849 AND value IS NOT NULL AND stay_id IN (SELECT stay_id FROM First_ICU_Stay)), vasoactive_agent AS (SELECT ie.stay_id, ie.starttime, ie.itemid, ie.rate AS vaso_rate FROM `physionet-data.mimiciv_3_1_icu.inputevents` ie JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id WHERE ie.itemid IN (221906, 221289, 221662, 221653) AND ie.stay_id IN (SELECT stay_id FROM First_ICU_Stay) AND ie.starttime BETWEEN icu.intime AND DATETIME_ADD(icu.intime, INTERVAL '1' DAY)), pafi AS (SELECT ie.stay_id, MIN(CASE WHEN vd.stay_id IS NULL THEN pao2fio2ratio END) AS pao2fio2ratio_novent, MIN(CASE WHEN vd.stay_id IS NOT NULL THEN pao2fio2ratio END) AS pao2fio2ratio_vent FROM First_ICU_Stay ie INNER JOIN `physionet-data.mimiciv_3_1_derived.bg` bg ON ie.hadm_id = bg.hadm_id LEFT JOIN ventilation_events vd ON ie.stay_id = vd.stay_id AND bg.charttime = vd.charttime LEFT JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id WHERE bg.specimen = 'ART.' AND bg.charttime BETWEEN icu.intime AND DATETIME_ADD(icu.intime, INTERVAL '1' DAY) GROUP BY ie.stay_id), vasopressors AS (SELECT stay_id, MAX(CASE WHEN itemid = 221906 THEN vaso_rate END) AS rate_norepinephrine, MAX(CASE WHEN itemid = 221289 THEN vaso_rate END) AS rate_epinephrine, MAX(CASE WHEN itemid = 221662 THEN vaso_rate END) AS rate_dopamine, MAX(CASE WHEN itemid = 221653 THEN vaso_rate END) AS rate_dobutamine FROM vasoactive_agent GROUP BY stay_id), scorecomp AS (SELECT ie.stay_id, pf.pao2fio2ratio_novent, pf.pao2fio2ratio_vent, labs.platelets_min, labs.bilirubin_total_max AS bilirubin_max, vital.mbp_min, vaso.rate_norepinephrine, vaso.rate_epinephrine, vaso.rate_dopamine, vaso.rate_dobutamine, gcs.gcs_min, labs.creatinine_max, uo.urineoutput AS uo_24hr FROM First_ICU_Stay ie LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_vitalsign` vital ON ie.stay_id = vital.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_gcs` gcs ON ie.stay_id = gcs.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_lab` labs ON ie.stay_id = labs.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_urine_output` uo ON ie.stay_id = uo.stay_id LEFT JOIN pafi pf ON ie.stay_id = pf.stay_id LEFT JOIN vasopressors vaso ON ie.stay_id = vaso.stay_id), scorecalc AS (SELECT stay_id, CASE WHEN pao2fio2ratio_vent < 100 THEN 4 WHEN pao2fio2ratio_vent < 200 THEN 3 WHEN pao2fio2ratio_novent < 300 THEN 2 WHEN pao2fio2ratio_vent < 300 THEN 2 WHEN pao2fio2ratio_novent < 400 THEN 1 WHEN pao2fio2ratio_vent < 400 THEN 1 ELSE 0 END AS respiration_sofa, CASE WHEN platelets_min < 20 THEN 4 WHEN platelets_min < 50 THEN 3 WHEN platelets_min < 100 THEN 2 WHEN platelets_min < 150 THEN 1 ELSE 0 END AS coagulation_sofa, CASE WHEN bilirubin_max >= 12.0 THEN 4 WHEN bilirubin_max >= 6.0 THEN 3 WHEN bilirubin_max >= 2.0 THEN 2 WHEN bilirubin_max >= 1.2 THEN 1 ELSE 0 END AS liver_sofa, CASE WHEN rate_dopamine > 15 OR rate_epinephrine > 0.1 OR rate_norepinephrine > 0.1 THEN 4 WHEN rate_dopamine > 5 OR rate_epinephrine <= 0.1 OR rate_norepinephrine <= 0.1 THEN 3 WHEN rate_dopamine > 0 OR rate_dobutamine > 0 THEN 2 WHEN mbp_min < 70 THEN 1 ELSE 0 END AS cardiovascular_sofa, CASE WHEN (gcs_min >= 13 AND gcs_min <= 14) THEN 1 WHEN (gcs_min >= 10 AND gcs_min <= 12) THEN 2 WHEN (gcs_min >= 6 AND gcs_min <= 9) THEN 3 WHEN gcs_min < 6 THEN 4 ELSE 0 END AS cns_sofa, CASE WHEN (creatinine_max >= 5.0) THEN 4 WHEN uo_24hr < 200 THEN 4 WHEN (creatinine_max >= 3.5 AND creatinine_max < 5.0) THEN 3 WHEN uo_24hr < 500 THEN 3 WHEN (creatinine_max >= 2.0 AND creatinine_max < 3.5) THEN 2 WHEN (creatinine_max >= 1.2 AND creatinine_max < 2.0) THEN 1 ELSE 0 END AS renal_sofa FROM scorecomp) SELECT stay_id, COALESCE(s.respiration_sofa, 0) + COALESCE(s.coagulation_sofa, 0) + COALESCE(s.liver_sofa, 0) + COALESCE(s.cardiovascular_sofa, 0) + COALESCE(s.cns_sofa, 0) + COALESCE(s.renal_sofa, 0) AS first_day_sofa_score FROM scorecalc s),
APSIII_Score AS (WITH ventilation_events AS (SELECT stay_id, charttime FROM `physionet-data.mimiciv_3_1_icu.chartevents` WHERE itemid = 223849 AND value IS NOT NULL AND stay_id IN (SELECT stay_id FROM First_ICU_Stay)), pa AS (SELECT ie.stay_id, bg.po2, ROW_NUMBER() OVER (PARTITION BY ie.stay_id ORDER BY bg.po2 DESC) AS rn FROM `physionet-data.mimiciv_3_1_derived.bg` bg INNER JOIN First_ICU_Stay ie ON bg.hadm_id = ie.hadm_id LEFT JOIN ventilation_events vd ON ie.stay_id = vd.stay_id AND bg.charttime = vd.charttime WHERE vd.stay_id IS NULL AND COALESCE(fio2, fio2_chartevents, 21) < 50 AND bg.po2 IS NOT NULL AND bg.specimen = 'ART.'), aa AS (SELECT ie.stay_id, bg.aado2, ROW_NUMBER() OVER (PARTITION BY ie.stay_id ORDER BY bg.aado2 DESC) AS rn FROM `physionet-data.mimiciv_3_1_derived.bg` bg INNER JOIN First_ICU_Stay ie ON bg.hadm_id = ie.hadm_id INNER JOIN ventilation_events vd ON ie.stay_id = vd.stay_id AND bg.charttime = vd.charttime WHERE vd.stay_id IS NOT NULL AND COALESCE(fio2, fio2_chartevents) >= 50 AND bg.aado2 IS NOT NULL AND bg.specimen = 'ART.'), acidbase AS (SELECT ie.stay_id, CASE WHEN ph < 7.20 THEN CASE WHEN pco2 < 50 THEN 12 ELSE 4 END WHEN ph < 7.30 THEN CASE WHEN pco2 < 30 THEN 9 WHEN pco2 < 40 THEN 6 WHEN pco2 < 50 THEN 3 ELSE 2 END WHEN ph < 7.35 THEN CASE WHEN pco2 < 30 THEN 9 WHEN pco2 < 45 THEN 0 ELSE 1 END WHEN ph < 7.45 THEN CASE WHEN pco2 < 30 THEN 5 WHEN pco2 < 45 THEN 0 ELSE 1 END WHEN ph < 7.50 THEN CASE WHEN pco2 < 30 THEN 5 WHEN pco2 < 35 THEN 0 WHEN pco2 < 45 THEN 2 ELSE 12 END WHEN ph < 7.60 THEN CASE WHEN pco2 < 40 THEN 3 ELSE 12 END ELSE CASE WHEN pco2 < 25 THEN 0 WHEN pco2 < 40 THEN 3 ELSE 12 END END AS acidbase_score FROM `physionet-data.mimiciv_3_1_derived.bg` bg INNER JOIN First_ICU_Stay ie ON bg.hadm_id = ie.hadm_id WHERE ph IS NOT NULL AND pco2 IS NOT NULL AND bg.specimen = 'ART.'), acidbase_max AS (SELECT stay_id, acidbase_score, ROW_NUMBER() OVER (PARTITION BY stay_id ORDER BY acidbase_score DESC) AS acidbase_rn FROM acidbase), arf AS (SELECT ie.stay_id, CASE WHEN labs.creatinine_max >= 1.5 AND uo.urineoutput < 410 AND icd.ckd = 0 THEN 1 ELSE 0 END AS arf FROM First_ICU_Stay ie LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_urine_output` uo ON ie.stay_id = uo.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_lab` labs ON ie.stay_id = labs.stay_id LEFT JOIN (SELECT hadm_id, MAX(CASE WHEN icd_version = 9 AND SUBSTR(icd_code, 1, 4) IN ('5854', '5855', '5856') THEN 1 WHEN icd_version = 10 AND SUBSTR(icd_code, 1, 4) IN ('N184', 'N185', 'N186') THEN 1 ELSE 0 END) AS ckd FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` GROUP BY hadm_id) icd ON ie.hadm_id = icd.hadm_id), vent AS (SELECT ie.stay_id, MAX(CASE WHEN v.stay_id IS NOT NULL THEN 1 ELSE 0 END) AS vent FROM First_ICU_Stay ie LEFT JOIN ventilation_events v ON ie.stay_id = v.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id WHERE DATETIME_DIFF(v.charttime, icu.intime, HOUR) < 24 GROUP BY ie.stay_id), cohort AS (SELECT ie.stay_id, vital.heart_rate_min, vital.heart_rate_max, vital.mbp_min, vital.mbp_max, vital.temperature_min, vital.temperature_max, vital.resp_rate_min, vital.resp_rate_max, pa.po2, aa.aado2, ab.acidbase_score, labs.hematocrit_min, labs.hematocrit_max, labs.wbc_min, labs.wbc_max, labs.creatinine_min, labs.creatinine_max, labs.bun_min, labs.bun_max, labs.sodium_min, labs.sodium_max, labs.albumin_min, labs.albumin_max, labs.bilirubin_total_min AS bilirubin_min, labs.bilirubin_total_max AS bilirubin_max, GREATEST(labs.glucose_max, vital.glucose_max) AS glucose_max, LEAST(labs.glucose_min, vital.glucose_min) AS glucose_min, vent.vent, uo.urineoutput, gcs.gcs_min, gcs.gcs_motor, gcs.gcs_verbal, gcs.gcs_eyes, gcs.gcs_unable, arf.arf FROM First_ICU_Stay ie LEFT JOIN pa ON ie.stay_id = pa.stay_id AND pa.rn = 1 LEFT JOIN aa ON ie.stay_id = aa.stay_id AND aa.rn = 1 LEFT JOIN acidbase_max ab ON ie.stay_id = ab.stay_id AND ab.acidbase_rn = 1 LEFT JOIN arf ON ie.stay_id = arf.stay_id LEFT JOIN vent ON ie.stay_id = vent.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_gcs` gcs ON ie.stay_id = gcs.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_vitalsign` vital ON ie.stay_id = vital.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_urine_output` uo ON ie.stay_id = uo.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_lab` labs ON ie.stay_id = labs.stay_id), score_min AS (SELECT c.stay_id, CASE WHEN heart_rate_min < 40 THEN 8 WHEN heart_rate_min < 50 THEN 5 WHEN heart_rate_min < 100 THEN 0 WHEN heart_rate_min < 110 THEN 1 WHEN heart_rate_min < 120 THEN 5 WHEN heart_rate_min < 140 THEN 7 WHEN heart_rate_min < 155 THEN 13 WHEN heart_rate_min >= 155 THEN 17 END AS hr_score, CASE WHEN mbp_min < 40 THEN 23 WHEN mbp_min < 60 THEN 15 WHEN mbp_min < 70 THEN 7 WHEN mbp_min < 80 THEN 6 WHEN mbp_min < 100 THEN 0 WHEN mbp_min < 120 THEN 4 WHEN mbp_min < 130 THEN 7 WHEN mbp_min < 140 THEN 9 WHEN mbp_min >= 140 THEN 10 END AS mbp_score, CASE WHEN temperature_min < 33.0 THEN 20 WHEN temperature_min < 33.5 THEN 16 WHEN temperature_min < 34.0 THEN 13 WHEN temperature_min < 35.0 THEN 8 WHEN temperature_min < 36.0 THEN 2 WHEN temperature_min < 40.0 THEN 0 WHEN temperature_min >= 40.0 THEN 4 END AS temp_score, CASE WHEN vent = 1 AND resp_rate_min < 14 THEN 0 WHEN resp_rate_min < 6 THEN 17 WHEN resp_rate_min < 12 THEN 8 WHEN resp_rate_min < 14 THEN 7 WHEN resp_rate_min < 25 THEN 0 WHEN resp_rate_min < 35 THEN 6 WHEN resp_rate_min < 40 THEN 9 WHEN resp_rate_min < 50 THEN 11 WHEN resp_rate_min >= 50 THEN 18 END AS resp_rate_score, CASE WHEN hematocrit_min < 41.0 THEN 3 WHEN hematocrit_min < 50.0 THEN 0 WHEN hematocrit_min >= 50.0 THEN 3 END AS hematocrit_score, CASE WHEN wbc_min < 1.0 THEN 19 WHEN wbc_min < 3.0 THEN 5 WHEN wbc_min < 20.0 THEN 0 WHEN wbc_min < 25.0 THEN 1 WHEN wbc_min >= 25.0 THEN 5 END AS wbc_score, CASE WHEN arf = 1 AND creatinine_min >= 1.5 THEN 10 WHEN arf = 1 THEN 0 WHEN creatinine_min < 0.5 THEN 3 WHEN creatinine_min < 1.5 THEN 0 WHEN creatinine_min < 1.95 THEN 4 WHEN creatinine_min >= 1.95 THEN 7 END AS creatinine_score, CASE WHEN bun_min < 17.0 THEN 0 WHEN bun_min < 20.0 THEN 2 WHEN bun_min < 40.0 THEN 7 WHEN bun_min < 80.0 THEN 11 WHEN bun_min >= 80.0 THEN 12 END AS bun_score, CASE WHEN sodium_min < 120 THEN 3 WHEN sodium_min < 135 THEN 2 WHEN sodium_min < 155 THEN 0 WHEN sodium_min >= 155 THEN 4 END AS sodium_score, CASE WHEN albumin_min < 2.0 THEN 11 WHEN albumin_min < 2.5 THEN 6 WHEN albumin_min < 4.5 THEN 0 WHEN albumin_min >= 4.5 THEN 4 END AS albumin_score, CASE WHEN bilirubin_min < 2.0 THEN 0 WHEN bilirubin_min < 3.0 THEN 5 WHEN bilirubin_min < 5.0 THEN 6 WHEN bilirubin_min < 8.0 THEN 8 WHEN bilirubin_min >= 8.0 THEN 16 END AS bilirubin_score, CASE WHEN glucose_min < 40 THEN 8 WHEN glucose_min < 60 THEN 9 WHEN glucose_min < 200 THEN 0 WHEN glucose_min < 350 THEN 3 WHEN glucose_min >= 350 THEN 5 END AS glucose_score FROM cohort c), score_max AS (SELECT c.stay_id, CASE WHEN heart_rate_max < 40 THEN 8 WHEN heart_rate_max < 50 THEN 5 WHEN heart_rate_max < 100 THEN 0 WHEN heart_rate_max < 110 THEN 1 WHEN heart_rate_max < 120 THEN 5 WHEN heart_rate_max < 140 THEN 7 WHEN heart_rate_max < 155 THEN 13 WHEN heart_rate_max >= 155 THEN 17 END AS hr_score, CASE WHEN mbp_max < 40 THEN 23 WHEN mbp_max < 60 THEN 15 WHEN mbp_max < 70 THEN 7 WHEN mbp_max < 80 THEN 6 WHEN mbp_max < 100 THEN 0 WHEN mbp_max < 120 THEN 4 WHEN mbp_max < 130 THEN 7 WHEN mbp_max < 140 THEN 9 WHEN mbp_max >= 140 THEN 10 END AS mbp_score, CASE WHEN temperature_max < 33.0 THEN 20 WHEN temperature_max < 33.5 THEN 16 WHEN temperature_max < 34.0 THEN 13 WHEN temperature_max < 35.0 THEN 8 WHEN temperature_max < 36.0 THEN 2 WHEN temperature_max < 40.0 THEN 0 WHEN temperature_max >= 40.0 THEN 4 END AS temp_score, CASE WHEN vent = 1 AND resp_rate_max < 14 THEN 0 WHEN resp_rate_max < 6 THEN 17 WHEN resp_rate_max < 12 THEN 8 WHEN resp_rate_max < 14 THEN 7 WHEN resp_rate_max < 25 THEN 0 WHEN resp_rate_max < 35 THEN 6 WHEN resp_rate_max < 40 THEN 9 WHEN resp_rate_max < 50 THEN 11 WHEN resp_rate_max >= 50 THEN 18 END AS resp_rate_score, CASE WHEN hematocrit_max < 41.0 THEN 3 WHEN hematocrit_max < 50.0 THEN 0 WHEN hematocrit_max >= 50.0 THEN 3 END AS hematocrit_score, CASE WHEN wbc_max < 1.0 THEN 19 WHEN wbc_max < 3.0 THEN 5 WHEN wbc_max < 20.0 THEN 0 WHEN wbc_max < 25.0 THEN 1 WHEN wbc_max >= 25.0 THEN 5 END AS wbc_score, CASE WHEN arf = 1 AND creatinine_max >= 1.5 THEN 10 WHEN arf = 1 THEN 0 WHEN creatinine_max < 0.5 THEN 3 WHEN creatinine_max < 1.5 THEN 0 WHEN creatinine_max < 1.95 THEN 4 WHEN creatinine_max >= 1.95 THEN 7 END AS creatinine_score, CASE WHEN bun_max < 17.0 THEN 0 WHEN bun_max < 20.0 THEN 2 WHEN bun_max < 40.0 THEN 7 WHEN bun_max < 80.0 THEN 11 WHEN bun_max >= 80.0 THEN 12 END AS bun_score, CASE WHEN sodium_max < 120 THEN 3 WHEN sodium_max < 135 THEN 2 WHEN sodium_max < 155 THEN 0 WHEN sodium_max >= 155 THEN 4 END AS sodium_score, CASE WHEN albumin_max < 2.0 THEN 11 WHEN albumin_max < 2.5 THEN 6 WHEN albumin_max < 4.5 THEN 0 WHEN albumin_max >= 4.5 THEN 4 END AS albumin_score, CASE WHEN bilirubin_max < 2.0 THEN 0 WHEN bilirubin_max < 3.0 THEN 5 WHEN bilirubin_max < 5.0 THEN 6 WHEN bilirubin_max < 8.0 THEN 8 WHEN bilirubin_max >= 8.0 THEN 16 END AS bilirubin_score, CASE WHEN glucose_max < 40 THEN 8 WHEN glucose_max < 60 THEN 9 WHEN glucose_max < 200 THEN 0 WHEN glucose_max < 350 THEN 3 WHEN glucose_max >= 350 THEN 5 END AS glucose_score FROM cohort c), scorecomp AS (SELECT co.*, CASE WHEN ABS(heart_rate_max - 75) > ABS(heart_rate_min - 75) THEN smax.hr_score WHEN ABS(heart_rate_max - 75) < ABS(heart_rate_min - 75) THEN smin.hr_score WHEN smax.hr_score >= smin.hr_score THEN smax.hr_score ELSE smin.hr_score END AS hr_score, CASE WHEN ABS(mbp_max - 90) > ABS(mbp_min - 90) THEN smax.mbp_score WHEN ABS(mbp_max - 90) < ABS(mbp_min - 90) THEN smin.mbp_score WHEN smax.mbp_score >= smin.mbp_score THEN smax.mbp_score ELSE smin.mbp_score END AS mbp_score, CASE WHEN ABS(temperature_max - 38) > ABS(temperature_min - 38) THEN smax.temp_score WHEN ABS(temperature_max - 38) < ABS(temperature_min - 38) THEN smin.temp_score WHEN smax.temp_score >= smin.temp_score THEN smax.temp_score ELSE smin.temp_score END AS temp_score, CASE WHEN ABS(resp_rate_max - 19) > ABS(resp_rate_min - 19) THEN smax.resp_rate_score WHEN ABS(resp_rate_max - 19) < ABS(resp_rate_min - 19) THEN smin.resp_rate_score WHEN smax.resp_rate_score >= smin.resp_rate_score THEN smax.resp_rate_score ELSE smin.resp_rate_score END AS resp_rate_score, CASE WHEN ABS(hematocrit_max - 45.5) > ABS(hematocrit_min - 45.5) THEN smax.hematocrit_score WHEN ABS(hematocrit_max - 45.5) < ABS(hematocrit_min - 45.5) THEN smin.hematocrit_score WHEN smax.hematocrit_score >= smin.hematocrit_score THEN smax.hematocrit_score ELSE smin.hematocrit_score END AS hematocrit_score, CASE WHEN ABS(wbc_max - 11.5) > ABS(wbc_min - 11.5) THEN smax.wbc_score WHEN ABS(wbc_max - 11.5) < ABS(wbc_min - 11.5) THEN smin.wbc_score WHEN smax.wbc_score >= smin.wbc_score THEN smax.wbc_score ELSE smin.wbc_score END AS wbc_score, CASE WHEN arf = 1 THEN smax.creatinine_score WHEN ABS(creatinine_max - 1) > ABS(creatinine_min - 1) THEN smax.creatinine_score WHEN ABS(creatinine_max - 1) < ABS(creatinine_min - 1) THEN smin.creatinine_score WHEN smax.creatinine_score >= smin.creatinine_score THEN smax.creatinine_score ELSE smin.creatinine_score END AS creatinine_score, smax.bun_score AS bun_score, CASE WHEN ABS(sodium_max - 145.5) > ABS(sodium_min - 145.5) THEN smax.sodium_score WHEN ABS(sodium_max - 145.5) < ABS(sodium_min - 145.5) THEN smin.sodium_score WHEN smax.sodium_score >= smin.sodium_score THEN smax.sodium_score ELSE smin.sodium_score END AS sodium_score, CASE WHEN ABS(albumin_max - 3.5) > ABS(albumin_min - 3.5) THEN smax.albumin_score WHEN ABS(albumin_max - 3.5) < ABS(albumin_min - 3.5) THEN smin.albumin_score WHEN smax.albumin_score >= smin.albumin_score THEN smax.albumin_score ELSE smin.albumin_score END AS albumin_score, smax.bilirubin_score AS bilirubin_score, CASE WHEN ABS(glucose_max - 130) > ABS(glucose_min - 130) THEN smax.glucose_score WHEN ABS(glucose_max - 130) < ABS(glucose_min - 130) THEN smin.glucose_score WHEN smax.glucose_score >= smin.glucose_score THEN smax.glucose_score ELSE smin.glucose_score END AS glucose_score, CASE WHEN urineoutput < 400 THEN 15 WHEN urineoutput < 600 THEN 8 WHEN urineoutput < 900 THEN 7 WHEN urineoutput < 1500 THEN 5 WHEN urineoutput < 2000 THEN 4 WHEN urineoutput < 4000 THEN 0 WHEN urineoutput >= 4000 THEN 1 END AS uo_score, CASE WHEN gcs_unable = 1 THEN 0 WHEN gcs_eyes = 1 THEN CASE WHEN gcs_verbal = 1 AND gcs_motor IN (1, 2) THEN 48 WHEN gcs_verbal = 1 AND gcs_motor IN (3, 4) THEN 33 WHEN gcs_verbal = 1 AND gcs_motor IN (5, 6) THEN 16 WHEN gcs_verbal IN (2, 3) AND gcs_motor IN (1, 2) THEN 29 WHEN gcs_verbal IN (2, 3) AND gcs_motor IN (3, 4) THEN 24 END WHEN gcs_eyes > 1 THEN CASE WHEN gcs_verbal = 1 AND gcs_motor IN (1, 2) THEN 29 WHEN gcs_verbal = 1 AND gcs_motor IN (3, 4) THEN 24 WHEN gcs_verbal = 1 AND gcs_motor IN (5, 6) THEN 15 WHEN gcs_verbal IN (2, 3) AND gcs_motor IN (1, 2) THEN 29 WHEN gcs_verbal IN (2, 3) AND gcs_motor IN (3, 4) THEN 24 WHEN gcs_verbal IN (2, 3) AND gcs_motor = 5 THEN 13 WHEN gcs_verbal IN (2, 3) AND gcs_motor = 6 THEN 10 WHEN gcs_verbal = 4 AND gcs_motor IN (1, 2, 3, 4) THEN 13 WHEN gcs_verbal = 4 AND gcs_motor = 5 THEN 8 WHEN gcs_verbal = 4 AND gcs_motor = 6 THEN 3 WHEN gcs_verbal = 5 AND gcs_motor IN (1, 2, 3, 4, 5) THEN 3 WHEN gcs_verbal = 5 AND gcs_motor = 6 THEN 0 END END AS gcs_score, CASE WHEN po2 IS NOT NULL THEN CASE WHEN po2 < 50 THEN 15 WHEN po2 < 70 THEN 5 WHEN po2 < 80 THEN 2 ELSE 0 END WHEN aado2 IS NOT NULL THEN CASE WHEN aado2 < 100 THEN 0 WHEN aado2 < 250 THEN 7 WHEN aado2 < 350 THEN 9 WHEN aado2 < 500 THEN 11 WHEN aado2 >= 500 THEN 14 ELSE 0 END END AS pao2_aado2_score FROM cohort co LEFT JOIN score_min smin ON co.stay_id = smin.stay_id LEFT JOIN score_max smax ON co.stay_id = smax.stay_id), score AS (SELECT s.*, (COALESCE(hr_score, 0) + COALESCE(mbp_score, 0) + COALESCE(temp_score, 0) + COALESCE(resp_rate_score, 0) + COALESCE(pao2_aado2_score, 0) + COALESCE(hematocrit_score, 0) + COALESCE(wbc_score, 0) + COALESCE(creatinine_score, 0) + COALESCE(uo_score, 0) + COALESCE(bun_score, 0) + COALESCE(sodium_score, 0) + COALESCE(albumin_score, 0) + COALESCE(bilirubin_score, 0) + COALESCE(glucose_score, 0) + COALESCE(acidbase_score, 0) + COALESCE(gcs_score, 0)) AS apsiii FROM scorecomp s) SELECT s.stay_id, s.apsiii, 1 / (1 + EXP(- (-4.4360 + 0.04726 * (s.apsiii)))) AS apsiii_prob FROM score s),
SAPSII_Score AS (WITH ventilation_events AS (SELECT stay_id, charttime FROM `physionet-data.mimiciv_3_1_icu.chartevents` WHERE itemid = 223849 AND value IS NOT NULL AND stay_id IN (SELECT stay_id FROM First_ICU_Stay)), cpap AS (SELECT co.stay_id, GREATEST(MIN(DATETIME_SUB(charttime, INTERVAL '1' HOUR)), co.starttime) AS starttime, LEAST(MAX(DATETIME_ADD(charttime, INTERVAL '4' HOUR)), co.endtime) AS endtime FROM (SELECT ie.stay_id, icu.intime AS starttime, DATETIME_ADD(icu.intime, INTERVAL '24' HOUR) AS endtime FROM First_ICU_Stay ie INNER JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id) co INNER JOIN `physionet-data.mimiciv_3_1_icu.chartevents` ce ON co.stay_id = ce.stay_id AND ce.charttime > co.starttime AND ce.charttime <= co.endtime WHERE ce.itemid = 226732 AND REGEXP_CONTAINS(LOWER(ce.value), '(cpap mask|bipap)') GROUP BY co.stay_id, co.starttime, co.endtime), surgflag AS (SELECT adm.hadm_id, CASE WHEN LOWER(curr_service) LIKE '%surg%' THEN 1 ELSE 0 END AS surgical, ROW_NUMBER() OVER (PARTITION BY adm.hadm_id ORDER BY transfertime) AS serviceorder FROM `physionet-data.mimiciv_3_1_hosp.admissions` adm LEFT JOIN `physionet-data.mimiciv_3_1_hosp.services` se ON adm.hadm_id = se.hadm_id WHERE adm.hadm_id IN (SELECT hadm_id FROM First_ICU_Stay)), comorb AS (SELECT hadm_id, MAX(CASE WHEN icd_version = 9 AND SUBSTR(icd_code, 1, 3) BETWEEN '042' AND '044' THEN 1 WHEN icd_version = 10 AND SUBSTR(icd_code, 1, 3) BETWEEN 'B20' AND 'B22' THEN 1 WHEN icd_version = 10 AND SUBSTR(icd_code, 1, 3) = 'B24' THEN 1 ELSE 0 END) AS aids, MAX(CASE WHEN icd_version = 9 AND (SUBSTR(icd_code, 1, 5) BETWEEN '20000' AND '20302' OR SUBSTR(icd_code, 1, 5) BETWEEN '20310' AND '20312' OR SUBSTR(icd_code, 1, 5) BETWEEN '20302' AND '20382' OR SUBSTR(icd_code, 1, 5) BETWEEN '20400' AND '20892' OR SUBSTR(icd_code, 1, 4) IN ('2386', '2733')) THEN 1 WHEN icd_version = 10 AND SUBSTR(icd_code, 1, 3) BETWEEN 'C81' AND 'C96' THEN 1 ELSE 0 END) AS hem, MAX(CASE WHEN icd_version = 9 AND (SUBSTR(icd_code, 1, 4) BETWEEN '1960' AND '1991' OR SUBSTR(icd_code, 1, 5) BETWEEN '20970' AND '20975' OR SUBSTR(icd_code, 1, 5) IN ('20979', '78951')) THEN 1 WHEN icd_version = 10 AND (SUBSTR(icd_code, 1, 3) BETWEEN 'C77' AND 'C79' OR SUBSTR(icd_code, 1, 4) = 'C800') THEN 1 ELSE 0 END) AS mets FROM `physionet-data.mimiciv_3_1_hosp.diagnoses_icd` WHERE hadm_id IN (SELECT hadm_id FROM First_ICU_Stay) GROUP BY hadm_id), pafi1 AS (SELECT co.stay_id, bg.charttime, pao2fio2ratio AS pao2fio2, CASE WHEN vd.stay_id IS NOT NULL THEN 1 ELSE 0 END AS vent, CASE WHEN cp.stay_id IS NOT NULL THEN 1 ELSE 0 END AS cpap FROM First_ICU_Stay co JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON co.stay_id = icu.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.bg` bg ON co.hadm_id = bg.hadm_id AND bg.specimen = 'ART.' AND bg.charttime > icu.intime AND bg.charttime <= DATETIME_ADD(icu.intime, INTERVAL '24' HOUR) LEFT JOIN ventilation_events vd ON co.stay_id = vd.stay_id AND bg.charttime = vd.charttime LEFT JOIN cpap cp ON co.stay_id = cp.stay_id AND bg.charttime > cp.starttime AND bg.charttime <= cp.endtime), pafi2 AS (SELECT stay_id, MIN(pao2fio2) AS pao2fio2_vent_min FROM pafi1 WHERE vent = 1 OR cpap = 1 GROUP BY stay_id), cohort AS (SELECT ie.stay_id, va.age, vital.heart_rate_max, vital.heart_rate_min, vital.sbp_max, vital.sbp_min, vital.temperature_max, vital.temperature_min, pf.pao2fio2_vent_min, uo.urineoutput, labs.bun_min, labs.bun_max, labs.wbc_min, labs.wbc_max, labs.potassium_min, labs.potassium_max, labs.sodium_min, labs.sodium_max, labs.bicarbonate_min, labs.bicarbonate_max, labs.bilirubin_total_min, labs.bilirubin_total_max, gcs.gcs_min, comorb.aids, comorb.hem, comorb.mets, CASE WHEN adm.admission_type = 'ELECTIVE' AND sf.surgical = 1 THEN 'ScheduledSurgical' WHEN adm.admission_type != 'ELECTIVE' AND sf.surgical = 1 THEN 'UnscheduledSurgical' ELSE 'Medical' END AS admissiontype FROM First_ICU_Stay ie INNER JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON ie.hadm_id = adm.hadm_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.age` va ON ie.hadm_id = va.hadm_id LEFT JOIN pafi2 pf ON ie.stay_id = pf.stay_id LEFT JOIN surgflag sf ON adm.hadm_id = sf.hadm_id AND sf.serviceorder = 1 LEFT JOIN comorb ON ie.hadm_id = comorb.hadm_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_gcs` gcs ON ie.stay_id = gcs.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_vitalsign` vital ON ie.stay_id = vital.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_urine_output` uo ON ie.stay_id = uo.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_lab` labs ON ie.stay_id = labs.stay_id), scorecomp AS (SELECT cohort.*, CASE WHEN age < 40 THEN 0 WHEN age < 60 THEN 7 WHEN age < 70 THEN 12 WHEN age < 75 THEN 15 WHEN age < 80 THEN 16 WHEN age >= 80 THEN 18 END AS age_score, CASE WHEN heart_rate_min < 40 THEN 11 WHEN heart_rate_max >= 160 THEN 7 WHEN heart_rate_max >= 120 THEN 4 WHEN heart_rate_min < 70 THEN 2 ELSE 0 END AS hr_score, CASE WHEN sbp_min < 70 THEN 13 WHEN sbp_min < 100 THEN 5 WHEN sbp_max >= 200 THEN 2 ELSE 0 END AS sysbp_score, CASE WHEN temperature_max >= 39.0 THEN 3 ELSE 0 END AS temp_score, CASE WHEN pao2fio2_vent_min < 100 THEN 11 WHEN pao2fio2_vent_min < 200 THEN 9 WHEN pao2fio2_vent_min >= 200 THEN 6 END AS pao2fio2_score, CASE WHEN urineoutput < 500.0 THEN 11 WHEN urineoutput < 1000.0 THEN 4 ELSE 0 END AS uo_score, CASE WHEN bun_max < 28.0 THEN 0 WHEN bun_max < 84.0 THEN 6 WHEN bun_max >= 84.0 THEN 10 END AS bun_score, CASE WHEN wbc_min < 1.0 THEN 12 WHEN wbc_max >= 20.0 THEN 3 ELSE 0 END AS wbc_score, CASE WHEN potassium_min < 3.0 THEN 3 WHEN potassium_max >= 5.0 THEN 3 ELSE 0 END AS potassium_score, CASE WHEN sodium_min < 125 THEN 5 WHEN sodium_max >= 145 THEN 1 ELSE 0 END AS sodium_score, CASE WHEN bicarbonate_min < 15.0 THEN 6 WHEN bicarbonate_min < 20.0 THEN 3 ELSE 0 END AS bicarbonate_score, CASE WHEN bilirubin_total_max < 4.0 THEN 0 WHEN bilirubin_total_max < 6.0 THEN 4 WHEN bilirubin_total_max >= 6.0 THEN 9 END AS bilirubin_score, CASE WHEN gcs_min < 3 THEN NULL WHEN gcs_min < 6 THEN 26 WHEN gcs_min < 9 THEN 13 WHEN gcs_min < 11 THEN 7 WHEN gcs_min < 14 THEN 5 WHEN gcs_min >= 14 THEN 0 END AS gcs_score, CASE WHEN aids = 1 THEN 17 WHEN hem = 1 THEN 10 WHEN mets = 1 THEN 9 ELSE 0 END AS comorbidity_score, CASE WHEN admissiontype = 'ScheduledSurgical' THEN 0 WHEN admissiontype = 'Medical' THEN 6 WHEN admissiontype = 'UnscheduledSurgical' THEN 8 END AS admissiontype_score FROM cohort), score AS (SELECT s.*, (COALESCE(age_score, 0) + COALESCE(hr_score, 0) + COALESCE(sysbp_score, 0) + COALESCE(temp_score, 0) + COALESCE(pao2fio2_score, 0) + COALESCE(uo_score, 0) + COALESCE(bun_score, 0) + COALESCE(wbc_score, 0) + COALESCE(potassium_score, 0) + COALESCE(sodium_score, 0) + COALESCE(bicarbonate_score, 0) + COALESCE(bilirubin_score, 0) + COALESCE(gcs_score, 0) + COALESCE(comorbidity_score, 0) + COALESCE(admissiontype_score, 0)) AS sapsii FROM scorecomp s) SELECT s.stay_id, s.sapsii, 1 / (1 + EXP(- (-7.7631 + 0.0737 * (s.sapsii) + 0.9971 * (LN(s.sapsii + 1))))) AS sapsii_prob FROM score s),
OASIS_Score AS (WITH ventilation_events AS (SELECT stay_id, charttime FROM `physionet-data.mimiciv_3_1_icu.chartevents` WHERE itemid = 223849 AND value IS NOT NULL AND stay_id IN (SELECT stay_id FROM First_ICU_Stay)), surgflag AS (SELECT ie.stay_id, MAX(CASE WHEN LOWER(curr_service) LIKE '%surg%' THEN 1 WHEN curr_service = 'ORTHO' THEN 1 ELSE 0 END) AS surgical FROM First_ICU_Stay ie LEFT JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_hosp.services` se ON ie.hadm_id = se.hadm_id AND se.transfertime < DATETIME_ADD(icu.intime, INTERVAL '1' DAY) GROUP BY ie.stay_id), vent AS (SELECT ie.stay_id, MAX(CASE WHEN v.stay_id IS NOT NULL THEN 1 ELSE 0 END) AS vent FROM First_ICU_Stay ie LEFT JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id LEFT JOIN ventilation_events v ON ie.stay_id = v.stay_id AND v.charttime >= icu.intime AND v.charttime <= DATETIME_ADD(icu.intime, INTERVAL '1' DAY) GROUP BY ie.stay_id), cohort AS (SELECT ie.stay_id, DATETIME_DIFF(icu.intime, adm.admittime, MINUTE) AS preiculos, ag.age, gcs.gcs_min, vital.heart_rate_max, vital.heart_rate_min, vital.mbp_max, vital.mbp_min, vital.resp_rate_max, vital.resp_rate_min, vital.temperature_max, vital.temperature_min, vent.vent AS mechvent, uo.urineoutput, CASE WHEN adm.admission_type = 'ELECTIVE' AND sf.surgical = 1 THEN 1 WHEN adm.admission_type IS NULL OR sf.surgical IS NULL THEN null ELSE 0 END AS electivesurgery FROM First_ICU_Stay ie INNER JOIN `physionet-data.mimiciv_3_1_icu.icustays` icu ON ie.stay_id = icu.stay_id INNER JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON ie.hadm_id = adm.hadm_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.age` ag ON ie.hadm_id = ag.hadm_id LEFT JOIN surgflag sf ON ie.stay_id = sf.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_gcs` gcs ON ie.stay_id = gcs.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_vitalsign` vital ON ie.stay_id = vital.stay_id LEFT JOIN `physionet-data.mimiciv_3_1_derived.first_day_urine_output` uo ON ie.stay_id = uo.stay_id LEFT JOIN vent ON ie.stay_id = vent.stay_id), scorecomp AS (SELECT co.stay_id, CASE WHEN preiculos < 10.2 THEN 5 WHEN preiculos < 297 THEN 3 WHEN preiculos < 1440 THEN 0 WHEN preiculos < 18708 THEN 2 ELSE 1 END AS preiculos_score, CASE WHEN age < 24 THEN 0 WHEN age <= 53 THEN 3 WHEN age <= 77 THEN 6 WHEN age <= 89 THEN 9 WHEN age >= 90 THEN 7 ELSE 0 END AS age_score, CASE WHEN gcs_min <= 7 THEN 10 WHEN gcs_min < 14 THEN 4 WHEN gcs_min = 14 THEN 3 ELSE 0 END AS gcs_score, CASE WHEN heart_rate_max > 125 THEN 6 WHEN heart_rate_min < 33 THEN 4 WHEN heart_rate_max >= 107 AND heart_rate_max <= 125 THEN 3 WHEN heart_rate_max >= 89 AND heart_rate_max <= 106 THEN 1 ELSE 0 END AS heart_rate_score, CASE WHEN mbp_min < 20.65 THEN 4 WHEN mbp_min < 51 THEN 3 WHEN mbp_max > 143.44 THEN 3 WHEN mbp_min >= 51 AND mbp_min < 61.33 THEN 2 ELSE 0 END AS mbp_score, CASE WHEN resp_rate_min < 6 THEN 10 WHEN resp_rate_max > 44 THEN 9 WHEN resp_rate_max > 30 THEN 6 WHEN resp_rate_max > 22 THEN 1 WHEN resp_rate_min < 13 THEN 1 ELSE 0 END AS resp_rate_score, CASE WHEN temperature_max > 39.88 THEN 6 WHEN temperature_min < 33.22 THEN 3 WHEN temperature_min > 35.93 AND temperature_min <= 36.39 THEN 2 WHEN temperature_max >= 36.89 AND temperature_max <= 39.88 THEN 2 WHEN temperature_min >= 33.22 AND temperature_min <= 35.93 THEN 4 WHEN temperature_max >= 33.22 AND temperature_max <= 35.93 THEN 4 ELSE 0 END AS temp_score, CASE WHEN urineoutput < 671.09 THEN 10 WHEN urineoutput > 6896.80 THEN 8 WHEN urineoutput >= 671.09 AND urineoutput <= 1426.99 THEN 5 WHEN urineoutput >= 1427.00 AND urineoutput <= 2544.14 THEN 1 ELSE 0 END AS urineoutput_score, CASE WHEN mechvent = 1 THEN 9 ELSE 0 END AS mechvent_score, CASE WHEN electivesurgery = 1 THEN 0 ELSE 6 END AS electivesurgery_score FROM cohort co), score AS (SELECT s.*, (COALESCE(age_score, 0) + COALESCE(preiculos_score, 0) + COALESCE(gcs_score, 0) + COALESCE(heart_rate_score, 0) + COALESCE(mbp_score, 0) + COALESCE(resp_rate_score, 0) + COALESCE(temp_score, 0) + COALESCE(urineoutput_score, 0) + COALESCE(mechvent_score, 0) + COALESCE(electivesurgery_score, 0)) AS oasis FROM scorecomp s) SELECT stay_id, oasis, 1 / (1 + EXP(- (-6.1746 + 0.1275 * (oasis)))) AS oasis_prob FROM score),
ICU_Readmission_Flag AS (SELECT stay_id, CASE WHEN next_hadm_id = hadm_id AND DATETIME_DIFF(next_icu_intime, outtime, DAY) > 1 AND DATETIME_DIFF(next_icu_intime, outtime, DAY) <= 30 THEN 1 ELSE 0 END AS icu_readmission_30_day FROM (SELECT stay_id, subject_id, hadm_id, intime, outtime, LEAD(hadm_id, 1) OVER (PARTITION BY subject_id ORDER BY intime ASC) as next_hadm_id, LEAD(intime, 1) OVER (PARTITION BY subject_id ORDER BY intime ASC) as next_icu_intime FROM `physionet-data.mimiciv_3_1_icu.icustays` WHERE subject_id IN (SELECT subject_id FROM Base_Cohort)) AS ranked_stays WHERE stay_id IN (SELECT stay_id FROM Base_Cohort)),

Mortality_Info AS (
    SELECT
        bc.hadm_id,
        COALESCE(adm.deathtime, IF(adm.hospital_expire_flag = 1, adm.dischtime, NULL), CAST(pat.dod AS DATETIME)) AS death_datetime,
        COALESCE(adm.deathtime, IF(adm.hospital_expire_flag = 1, adm.dischtime, NULL)) as in_hospital_death_datetime
    FROM Base_Cohort bc
    JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON bc.hadm_id = adm.hadm_id
    JOIN `physionet-data.mimiciv_3_1_hosp.patients` pat ON bc.subject_id = pat.subject_id
),
Outcomes AS (
    SELECT
        bc.hadm_id, bc.stay_id, mort.death_datetime,
        DATETIME_DIFF(adm.dischtime, adm.admittime, HOUR) / 24.0 AS hospital_los_days,
        LEAST(icu.icu_los_raw, DATETIME_DIFF(adm.dischtime, adm.admittime, HOUR) / 24.0) AS icu_los_days,
        CASE WHEN mort.in_hospital_death_datetime IS NOT NULL THEN 1 ELSE 0 END AS in_hospital_mortality_flag,
        CASE WHEN mort.death_datetime IS NOT NULL THEN 1 ELSE 0 END AS overall_mortality_flag,
        DATETIME_DIFF(mort.in_hospital_death_datetime, adm.admittime, HOUR) / 24.0 AS in_hospital_mortality_duration,
        DATETIME_DIFF(mort.death_datetime, adm.admittime, HOUR) / 24.0 AS overall_mortality_duration
    FROM Base_Cohort bc
    JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON bc.hadm_id = adm.hadm_id
    JOIN First_ICU_Stay icu ON bc.hadm_id = icu.hadm_id
    LEFT JOIN Mortality_Info mort ON bc.hadm_id = mort.hadm_id
),
Readmission_Outcome AS (
   WITH next_admission AS (SELECT hadm_id, subject_id, dischtime, LEAD(admittime, 1) OVER (PARTITION BY subject_id ORDER BY admittime) as next_admittime FROM `physionet-data.mimiciv_3_1_hosp.admissions`)
   SELECT hadm_id, CASE WHEN next_admittime IS NOT NULL AND DATETIME_DIFF(next_admittime, dischtime, DAY) <= 30 THEN 1 ELSE 0 END AS readmission_30_days
   FROM next_admission WHERE hadm_id IN (SELECT hadm_id FROM Base_Cohort)
),
MAKE_KRT_Outcomes AS (
   WITH all_krt_events AS (
       SELECT hadm_id, CAST(chartdate AS DATETIME) as krt_time FROM `physionet-data.mimiciv_3_1_hosp.procedures_icd` WHERE icd_code IN ('3995', '5498', '3895', '5A1D70Z', '5A1D80Z', '5A1D90Z')
       UNION ALL SELECT i.hadm_id, pe.starttime as krt_time FROM `physionet-data.mimiciv_3_1_icu.procedureevents` pe JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON pe.stay_id = i.stay_id WHERE pe.itemid IN (225441, 225802, 225803, 225805, 225809, 225955)
       UNION ALL SELECT i.hadm_id, ce.charttime as krt_time FROM `physionet-data.mimiciv_3_1_icu.chartevents` ce JOIN `physionet-data.mimiciv_3_1_icu.icustays` i ON ce.stay_id = i.stay_id WHERE ce.itemid IN (226118, 227357, 225725, 226499, 224154, 225183, 227438, 224191, 228004, 228005, 228006, 224144, 224145, 224149, 224150, 224151, 224152, 224153, 225810, 225806, 225807, 227639, 225959, 225951, 225952, 225961, 225953, 225963, 225965, 227638, 227640)
   ), first_krt_event AS (
       SELECT bc.hadm_id, ROW_NUMBER() OVER (PARTITION BY bc.hadm_id ORDER BY krt.krt_time ASC) as rn
       FROM Base_Cohort bc JOIN First_ICU_Stay icu ON bc.hadm_id = icu.hadm_id JOIN `physionet-data.mimiciv_3_1_hosp.admissions` adm ON bc.hadm_id = adm.hadm_id JOIN all_krt_events krt ON bc.hadm_id = krt.hadm_id
       LEFT JOIN Patient_History hist ON bc.hadm_id = hist.hadm_id
       WHERE IFNULL(hist.history_hemodialysis, 0) = 0 AND IFNULL(hist.had_peritoneal_dialysis, 0) = 0 AND krt.krt_time >= icu.intime AND krt.krt_time <= LEAST(adm.dischtime, DATETIME_ADD(icu.intime, INTERVAL 30 DAY))
   )
   SELECT hadm_id, 1 AS make_krt FROM first_krt_event WHERE rn = 1
)


SELECT

  bc.subject_id, bc.hadm_id, icu.stay_id, pat.gender, pat.anchor_age, bc.admittime, adm.dischtime,
  outcomes.death_datetime,
  outcomes.in_hospital_mortality_flag AS hospital_expire_flag,

  rac.aki_icd_code, preg.pregnancy_icd_codes, con.congenital_anomaly_icd_codes, hem_mal.hematolymphoid_icd_codes, mal.malignancy_icd_codes, aids.aids_icd_codes,

  IFNULL(hist.history_hemodialysis, 0) AS history_hemodialysis, IFNULL(hist.had_peritoneal_dialysis, 0) AS had_peritoneal_dialysis, IFNULL(hist.history_renal_transplant, 0) AS history_renal_transplant,
  IFNULL(niv_flag.had_niv, 0) AS had_niv, IFNULL(imv_flag.had_imv, 0) AS had_imv, IFNULL(rrt_flag.had_rrt, 0) AS had_rrt,
  bcr.baseline_creatinine,

  IFNULL(flags.has_t1d, 0) AS has_t1d, IFNULL(flags.has_t2d, 0) AS has_t2d, IFNULL(flags.has_hypertension, 0) AS has_hypertension, IFNULL(flags.has_heart_failure, 0) AS has_heart_failure, IFNULL(flags.has_cerebrovascular_disease, 0) AS has_cerebrovascular_disease, IFNULL(flags.has_respiratory_failure, 0) AS has_respiratory_failure, IFNULL(flags.has_sepsis, 0) AS has_sepsis, IFNULL(flags.has_cirrhosis, 0) AS has_cirrhosis, IFNULL(flags.has_ckd, 0) AS has_ckd, IFNULL(flags.has_leukemia, 0) AS has_leukemia, IFNULL(flags.has_lymphoma, 0) AS has_lymphoma, IFNULL(flags.has_aids, 0) AS has_aids,

  bf.first_heart_rate, bf.first_mbp, bf.first_temp_f, bf.first_gcs_motor, bf.first_gcs_verbal, bf.first_gcs_eye, bf.first_hb, bf.first_wbc, bf.first_mch, bf.first_mcv, bf.first_rdw_cv, bf.first_platelet_count, bf.first_abs_neutrophil, bf.first_abs_lymphocyte, bf.first_abs_monocyte, bf.first_glucose_lab, bf.first_hdl, bf.first_creatinine, bf.first_bun, bf.first_albumin, bf.first_pao2, bf.first_ph_arterial,

  outcomes.icu_los_days, outcomes.hospital_los_days, IFNULL(readmit.readmission_30_days, 0) AS readmission_30_days, IFNULL(icu_readmit.icu_readmission_30_day, 0) AS icu_readmission_30_day,

  outcomes.in_hospital_mortality_flag AS make_death,
  IFNULL(make_krt.make_krt, 0) AS make_krt,
  CASE WHEN make_creat.make_final_creat_value >= (2 * bcr.baseline_creatinine) THEN 1 ELSE 0 END AS make_persistent_renal_dysfunction,

  outcomes.in_hospital_mortality_duration, outcomes.overall_mortality_flag, outcomes.overall_mortality_duration,

  IFNULL(crt.renal_transplant_current, 0) AS renal_transplant_current,

  lods.lods_score, ci.charlson_comorbidity_index, sofa.first_day_sofa_score,
  apsiii.apsiii, apsiii.apsiii_prob, sapsii.sapsii, sapsii.sapsii_prob, oasis.oasis, oasis.oasis_prob
FROM Base_Cohort AS bc
INNER JOIN `physionet-data.mimiciv_3_1_hosp.admissions` AS adm ON bc.hadm_id = adm.hadm_id
INNER JOIN `physionet-data.mimiciv_3_1_hosp.patients` AS pat ON bc.subject_id = pat.subject_id
INNER JOIN First_ICU_Stay AS icu ON bc.hadm_id = icu.hadm_id
LEFT JOIN Relevant_AKI_Codes AS rac ON bc.hadm_id = rac.hadm_id
LEFT JOIN Pregnancy_Codes AS preg ON bc.hadm_id = preg.hadm_id
LEFT JOIN Congenital_Codes AS con ON bc.hadm_id = con.hadm_id
LEFT JOIN Hematolymphoid_Malignancy_Codes AS hem_mal ON bc.hadm_id = hem_mal.hadm_id
LEFT JOIN Malignancy_Codes AS mal ON bc.hadm_id = mal.hadm_id
LEFT JOIN AIDS_Codes AS aids ON bc.hadm_id = aids.hadm_id
LEFT JOIN Comorbidities_Flags AS flags ON bc.hadm_id = flags.hadm_id
LEFT JOIN Patient_History AS hist ON bc.hadm_id = hist.hadm_id
LEFT JOIN NIV_Flag AS niv_flag ON bc.hadm_id = niv_flag.hadm_id
LEFT JOIN IMV_Flag AS imv_flag ON bc.hadm_id = imv_flag.hadm_id
LEFT JOIN RRT_Flag AS rrt_flag ON bc.hadm_id = rrt_flag.hadm_id
LEFT JOIN Baseline_Creatinine AS bcr ON bc.hadm_id = bcr.hadm_id
LEFT JOIN Baseline_Features AS bf ON bc.hadm_id = bf.hadm_id
LEFT JOIN Outcomes AS outcomes ON bc.hadm_id = outcomes.hadm_id
LEFT JOIN Readmission_Outcome AS readmit ON bc.hadm_id = readmit.hadm_id
LEFT JOIN ICU_Readmission_Flag AS icu_readmit ON bc.stay_id = icu_readmit.stay_id
LEFT JOIN MAKE_KRT_Outcomes AS make_krt ON bc.hadm_id = make_krt.hadm_id
LEFT JOIN MAKE_Creatinine_Outcomes AS make_creat ON bc.hadm_id = make_creat.hadm_id
LEFT JOIN Current_Renal_Transplant AS crt ON bc.hadm_id = crt.hadm_id
LEFT JOIN Charlson_Index AS ci ON bc.hadm_id = ci.hadm_id
LEFT JOIN LODS_Scores AS lods ON icu.stay_id = lods.stay_id
LEFT JOIN First_Day_SOFA AS sofa ON icu.stay_id = sofa.stay_id
LEFT JOIN APSIII_Score AS apsiii ON icu.stay_id = apsiii.stay_id
LEFT JOIN SAPSII_Score AS sapsii ON icu.stay_id = sapsii.stay_id
LEFT JOIN OASIS_Score AS oasis ON icu.stay_id = oasis.stay_id
ORDER BY bc.subject_id
);